#include <iostream>
#include <string>

class Book {
    std::string m_title;
    std::string m_author;
    int m_year;

public:
    Book(const std::string& title, const std::string& author, int year)
        : m_title{title}, m_author{author}, m_year{year} {}

    void print() const {
        std::cout << "Title: "  << m_title  << '\n';
        std::cout << "Author: " << m_author << '\n';
        std::cout << "Year: "   << m_year   << '\n';
    }
};

int main() {
    std::string title{};
    std::string author{};
    int year{};

    std::cin >> title >> author >> year;

    Book b{title, author, year};
    b.print();

    return 0;
}

