exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <string>

class Sensor {
    std::string m_name;
    int m_count;
    double m_sum;

public:
    Sensor(const std::string& name)
        : m_name{name}, m_count{0}, m_sum{0.0} {}

    Sensor()
        : m_name{"Unknown"}, m_count{0}, m_sum{0.0} {}

    void addReading(double temp) {
        m_sum += temp;
        ++m_count;
    }

    void print() const {
        double avg = (m_count > 0) ? m_sum / m_count : 0.0;
        std::cout << "Sensor: "   << m_name   << '\n';
        std::cout << "Readings: " << m_count  << '\n';
        std::cout << "Average: "  << std::fixed << std::setprecision(2) << avg << '\n';
    }
};

int main() {
    std::string name{};
    int n{};

    std::cin >> name >> n;

    Sensor s{name};

    for (int i = 0; i < n; ++i) {
        double temp{};
        std::cin >> temp;
        s.addReading(temp);
    }

    s.print();

    return 0;
}
